  ('social-worker-moex-07043', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「生命軌跡或軌道（life trajectory）」是生命歷程觀點（life course perspective）的重要概念之一，它係指：', '["同樣的歷史事件，對於生活在同一個世代的個人，往往產生相同的影響，經歷相類似的生活模式", "人類的行為發展某些部分會受到遺傳所決定，會依循著典型的發展途徑而成長", "每個人之前的生活經驗會累積成一種有別於他人的生命發展路線", "每個人的人生歷程就是由舊的階段轉換（transition）到新的階段，而形成的規則性現象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
